.colleague-finder {
  max-width: 960px;
  margin: 0 auto;
  padding: 16px;
  color: #1f2933;
}

.heading {
  text-align: center;
  font-weight: 600;
  margin-bottom: 20px;
}

.search-row {
  display: flex;
  gap: 12px;
  align-items: stretch;
  margin-bottom: 10px;
  flex-wrap: wrap;
}

.search-input {
  position: relative;
  flex: 1;
}

.search-input .input-icon {
  position: absolute;
  top: 50%;
  left: 12px;
  transform: translateY(-50%);
  color: #8a8f98;
}

.search-input .form-control {
  padding-left: 34px;
  height: 42px;
  border-radius: 12px;
}

.search-btn {
  min-width: 120px;
  border-radius: 12px;
}

.subtle-text {
  color: #6b7480;
  margin: 8px 0 16px;
}

.placeholder {
  text-align: center;
  padding: 40px 12px;
  border: 1px dashed #c7ccd3;
  border-radius: 14px;
  color: #6b7480;
}

.card-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 16px;
}

.profile-card {
  background: #fff;
  border: 1px solid #e1e5eb;
  border-radius: 18px;
  padding: 16px;
  box-shadow: 0 6px 14px rgba(0, 0, 0, 0.05);
  cursor: pointer;
  transition: transform 0.1s ease, box-shadow 0.1s ease;
  outline: none;
}

.profile-card:focus,
.profile-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 10px 22px rgba(0, 0, 0, 0.08);
}

.profile-card .card-header {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 12px;
}

.avatar-circle,
.avatar-photo {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  display: grid;
  place-items: center;
  background: #eef1f6;
  color: #7a828c;
  flex-shrink: 0;
}

.avatar-photo {
  background-size: cover;
  background-position: center;
}

.card-title .name {
  font-weight: 600;
  font-size: 16px;
}

.card-title .title {
  font-size: 13px;
}

.card-title .muted {
  color: #8a8f98;
}

.card-meta li {
  display: flex;
  justify-content: space-between;
  font-size: 13px;
  margin-bottom: 6px;
}

.card-meta .label {
  color: #6b7480;
}

.card-meta .value {
  font-weight: 600;
  color: #1f2933;
}

.card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 12px;
  color: #3b6cc2;
}

.card-footer .cta {
  font-weight: 600;
}

.user-profile-modal .modal-content {
  border-radius: 14px;
}

.user-profile-modal-body {
  display: grid;
  grid-template-columns: 90px 1fr;
  gap: 12px;
  align-items: start;
}

.modal-avatar {
  width: 90px;
  height: 90px;
  border-radius: 50%;
  background-size: cover;
  background-position: center;
  background-color: #eef1f6;
}

.modal-avatar.placeholder {
  display: grid;
  place-items: center;
  color: #7a828c;
}

.modal-meta .meta-row {
  display: flex;
  justify-content: space-between;
  margin-bottom: 6px;
  font-size: 13px;
}

.modal-meta .label {
  color: #6b7480;
}

.modal-meta .value {
  font-weight: 600;
  color: #1f2933;
}

@media (max-width: 640px) {
  .search-row {
    flex-direction: column;
  }

  .search-btn {
    width: 100%;
  }

  .user-profile-modal-body {
    grid-template-columns: 1fr;
    text-align: center;
  }
}

